# --- BUG: common in loop-generated functions ---
handlers = []
for event_id in range(3):
    def handle():
        print(f'Handling event {event_id}')  # captures 'event_id' by reference
    handlers.append(handle)

# By the time we call them, the loop is done and event_id = 2
for h in handlers:
    h()   # All print: 'Handling event 2'

print('--- Fixed version ---')
# FIX 1: default argument captures value at function creation time
handlers_fixed = []
for event_id in range(3):
    def handle(eid=event_id):
        print(f'Handling event {eid}')
    handlers_fixed.append(handle)

for h in handlers_fixed:
    h()   # Prints 0, 1, 2 correctly

# FIX 2: functools.partial (cleaner for complex cases)
from functools import partial

def handle_event(eid):
    print(f'Handling event {eid}')

handlers_partial = [partial(handle_event, i) for i in range(3)]
for h in handlers_partial:
    h()   # Prints 0, 1, 2 correctly

