_MISSING = object()  # unique object — nothing else is this

def get_config(key: str, default=_MISSING):
    if key in config:
        return config[key]
    if default is _MISSING:
        raise KeyError(f'Config key not found: {key}')
    return default

# Now callers can pass None as a valid default:
get_config('debug_mode', default=None)   # returns None if key missing
get_config('required_key')              # raises KeyError if key missing

import re

# Before walrus
log_lines = ['INFO: ok', 'ERROR: 404', 'INFO: ok']
for line in log_lines:
    match = re.search(r'ERROR: (\d+)', line)
    if match:
        print(f'Error code: {match.group(1)}')

# With walrus — cleaner
for line in log_lines:
    if m := re.search(r'ERROR: (\d+)', line):
        print(f'Error code: {m.group(1)}')

# Bad — magic numbers
if retry_count > 3:
    time.sleep(0.5)
    if error_code == 429:
        raise RateLimitError()

# Good — named constants
MAX_RETRIES = 3
BACKOFF_SECONDS = 0.5
HTTP_TOO_MANY_REQUESTS = 429

if retry_count > MAX_RETRIES:
    time.sleep(BACKOFF_SECONDS)
    if error_code == HTTP_TOO_MANY_REQUESTS:
        raise RateLimitError()
